def find_peak_element(nums: list[int]) -> int:
    n = len(nums)
    if n == 1:
        return nums[0]

    low = 0
    high = n - 1

    while low < high:
        mid = (low + high) // 2

        if nums[mid] < nums[mid + 1]:
            # We are on an ascending slope, so a peak must be to the right.
            low = mid + 1
        else:
            # We are on a descending slope or at a peak, so a peak could be mid or to its left.
            high = mid

    # When the loop terminates, low == high, and this index points to a peak element.
    return nums[low]
